import os


def delete_uploaded_file(filename: str, base_directory: str = "uploads") -> dict:
    """
    Deletes a user's uploaded file from the specified base directory.
    
    Canonicalizes and validates file paths to ensure the resolved path
    stays within the intended base directory (preventing path traversal attacks).
    
    Args:
        filename: The name of the file to delete.
        base_directory: The base directory where uploads are stored. Defaults to 'uploads'.
    
    Returns:
        A dictionary with 'success' (bool) and 'message' (str) keys.
    """
    if not filename or not isinstance(filename, str):
        return {
            "success": False,
            "message": "Invalid filename provided. Filename must be a non-empty string."
        }

    # Strip any leading/trailing whitespace
    filename = filename.strip()

    if not filename:
        return {
            "success": False,
            "message": "Filename cannot be empty or whitespace only."
        }

    # Resolve the base directory to an absolute, canonical path
    base_dir_resolved = os.path.realpath(os.path.abspath(base_directory))

    # Check that the base directory exists
    if not os.path.isdir(base_dir_resolved):
        return {
            "success": False,
            "message": f"Base directory '{base_directory}' does not exist."
        }

    # Construct the full file path by joining base directory and filename
    requested_path = os.path.join(base_dir_resolved, filename)

    # Canonicalize the requested path to resolve any '..' , '.' , symlinks, etc.
    resolved_path = os.path.realpath(os.path.abspath(requested_path))

    # Ensure the resolved path is within the base directory
    # Use os.sep to ensure we check for proper directory boundary
    if not resolved_path.startswith(base_dir_resolved + os.sep) and resolved_path != base_dir_resolved:
        return {
            "success": False,
            "message": "Access denied. The specified file path is outside the allowed directory."
        }

    # Additional check: the resolved path should not be the base directory itself
    if resolved_path == base_dir_resolved:
        return {
            "success": False,
            "message": "Access denied. Cannot delete the base directory itself."
        }

    # Check if the file exists
    if not os.path.exists(resolved_path):
        return {
            "success": False,
            "message": f"File '{filename}' does not exist in the uploads directory."
        }

    # Ensure it's a file and not a directory
    if not os.path.isfile(resolved_path):
        return {
            "success": False,
            "message": f"'{filename}' is not a file. Only files can be deleted."
        }

    # Check if the path is a symbolic link (additional security measure)
    if os.path.islink(requested_path):
        # Re-verify the symlink target is within the base directory
        link_target = os.path.realpath(requested_path)
        if not link_target.startswith(base_dir_resolved + os.sep):
            return {
                "success": False,
                "message": "Access denied. Symbolic link points outside the allowed directory."
            }

    # Attempt to delete the file
    try:
        os.remove(resolved_path)
        return {
            "success": True,
            "message": f"File '{filename}' has been successfully deleted."
        }
    except PermissionError:
        return {
            "success": False,
            "message": f"Permission denied. Unable to delete '{filename}'."
        }
    except OSError as e:
        return {
            "success": False,
            "message": f"An error occurred while deleting '{filename}': {str(e)}"
        }


